def add_to_parser(self, parser: _OptionParser, ctx: Context) -> None:
    if self.multiple:
        action = "append"
    elif self.count:
        action = "count"
    else:
        action = "store"

    if self.is_flag:
        action = f"{action}_const"

        if self.is_bool_flag and self.secondary_opts:
            parser.add_option(
                obj=self, opts=self.opts, dest=self.name, action=action, const=True
            )
            parser.add_option(
                obj=self,
                opts=self.secondary_opts,
                dest=self.name,
                action=action,
                const=False,
            )
        else:
            parser.add_option(
                obj=self,
                opts=self.opts,
                dest=self.name,
                action=action,
                const=self.flag_value,
            )
    else:
        parser.add_option(
            obj=self,
            opts=self.opts,
            dest=self.name,
            action=action,
            nargs=self.nargs,
        )

